// Normalize row and detect shortened Maps link.
const item = $input.first().json;
const get = (name) => {
  const v = item[name];
  if (v !== undefined && v !== null) return v;
  const key = Object.keys(item).find(k => k.trim() === name);
  return key !== undefined ? item[key] : undefined;
};
// Form column is 'Capture Location (GPS)'; fallback for future rename
const captureLocation = (get('Capture Location (GPS)') ?? get('Capture Location') ?? '').toString().trim();
const isShortLink = /^(https?:\/\/)?(www\.)?(maps\.app\.goo\.gl|goo\.gl\/maps)\/\S+/i.test(captureLocation);
return [{ json: { ...item, captureLocation, isShortLink } }];

// Parse GPS from HTTP response. Uses actual form column names.
try {
  const form = $('Normalize and Check').first().json;
  const get = (name) => {
    const v = form[name];
    if (v !== undefined && v !== null) return v;
    const key = Object.keys(form).find(k => k.trim() === name);
    return key !== undefined ? form[key] : undefined;
  };
  const bookingUid        = (get('Booking ID')                          || '').toString().trim();
  const cleanerIdFromForm = (get('Cleaner ID')                          || '').toString().trim();
  const confirmCheckout   = (get('Confirm Checkout')                    || '').toString().trim();
  const issueReported     = (get('Any maintenance issues to report?')   || '').toString().trim();
  const issueType         = (get('Issue Type')                          || '').toString().trim();
  const description       = (get('Issue Description')                   || '').toString().trim();
  const photoUrl          = (get('Photo of Issue')                      || '').toString().trim();
  const priority          = (get('Issue Priority')                      || '').toString().trim();
  const lowStockAlert     = (get('Low Stock Alert')                     || '').toString().trim();
  if (!bookingUid) throw new Error('Booking ID is missing');
  if (!cleanerIdFromForm) throw new Error('Cleaner ID is missing');
  if (!confirmCheckout || confirmCheckout.toLowerCase() !== 'yes') throw new Error('Checkout not confirmed');

  const resp = $input.first().json;
  const raw = (resp.data != null ? resp.data : resp.body != null ? resp.body : typeof resp === 'string' ? resp : JSON.stringify(resp));
  const str = typeof raw === 'string' ? raw : String(raw);
  let m = str.match(/q=(-?\d+\.\d+)%2C(-?\d+\.\d+)/);
  if (!m) m = str.match(/(-?\d+\.\d+),(-?\d+\.\d+)/);
  if (!m) m = str.match(/3d(-?\d+\.\d+)[^4]*4d(-?\d+\.\d+)/);
  const gpsLat = m ? m[1] : '';
  const gpsLng = m ? m[2] : '';

  // Individual supply columns from the form
  const supplyColMap = {
    "Trash Bags \u2014 Qty Used": "Trash Bags",
    "All-Purpose Cleaner \u2014 Qty Used": "All-Purpose Cleaner",
    "Glass Cleaner \u2014 Qty Used": "Glass Cleaner",
    "Disinfectant \u2014 Qty Used": "Disinfectant",
    "Toilet Cleaner \u2014 Qty Used": "Toilet Cleaner",
    "Floor Cleaner \u2014 Qty Used": "Floor Cleaner",
    "Sponges \u2014 Qty Used": "Sponges",
    "Paper Towels \u2014 Qty Used": "Paper Towels",
    "Laundry Detergent \u2014 Qty Used": "Laundry Detergent",
    "Fabric Softener \u2014 Qty Used": "Fabric Softener",
    "Dish Soap \u2014 Qty Used": "Dish Soap",
    "Air Freshener \u2014 Qty Used": "Air Freshener",
    "Microfiber Cloths \u2014 Qty Used": "Microfiber Cloths",
    "Mop Pads \u2014 Qty Used": "Mop Pads",
  };
  const supplies = [];
  for (const [col, itemName] of Object.entries(supplyColMap)) {
    const raw = (get(col) || '').toString().trim();
    const qty = raw === '' ? 0 : parseInt(raw, 10);
    if (!isNaN(qty) && qty > 0) supplies.push({ itemName, quantityUsed: qty });
  }

  return [{ json: {
    bookingUid, cleanerIdFromForm, gpsLat, gpsLng,
    submissionTimestamp: (get('Timestamp') || new Date().toISOString()).toString(),
    processingStatus: 'PENDING', resultMessage: '', processedAt: '',
    hasError: false,
    issueReported, issueType, description, photoUrl, priority, lowStockAlert,
    supplies
  } }];
} catch (err) {
  const form = $('Normalize and Check').first().json;
  const get = (name) => { const v = form[name]; if (v !== undefined && v !== null) return v; const key = Object.keys(form).find(k => k.trim() === name); return key !== undefined ? form[key] : undefined; };
  return [{ json: { hasError: true, errorMessage: err.message, bookingUid: (get('Booking ID') || 'unknown').toString(), cleanerIdFromForm: (get('Cleaner ID') || '').toString(), submissionTimestamp: new Date().toISOString() } }];
}

// ParseAndValidate: full URL, lat,lng, or DMS. Uses actual form column names.
// GPS parse failure returns empty coords; 4B will reject (design rule #5).
try {
  const item = $('Normalize and Check').first().json;
  const get = (name) => {
    const v = item[name];
    if (v !== undefined && v !== null) return v;
    const key = Object.keys(item).find(k => k.trim() === name);
    return key !== undefined ? item[key] : undefined;
  };
  const bookingUid        = (get('Booking ID')                          || '').toString().trim();
  const cleanerIdFromForm = (get('Cleaner ID')                          || '').toString().trim();
  const confirmCheckout   = (get('Confirm Checkout')                    || '').toString().trim();
  const issueReported     = (get('Any maintenance issues to report?')   || '').toString().trim();
  const issueType         = (get('Issue Type')                          || '').toString().trim();
  const description       = (get('Issue Description')                   || '').toString().trim();
  const photoUrl          = (get('Photo of Issue')                      || '').toString().trim();
  const priority          = (get('Issue Priority')                      || '').toString().trim();
  const lowStockAlert     = (get('Low Stock Alert')                     || '').toString().trim();
  const mapsLink = (item.captureLocation != null ? item.captureLocation : (get('Capture Location (GPS)') || get('Capture Location') || '')).toString().trim();

  if (!bookingUid) throw new Error('Booking ID is missing');
  if (!cleanerIdFromForm) throw new Error('Cleaner ID is missing');
  if (!confirmCheckout || confirmCheckout.toLowerCase() !== 'yes') throw new Error('Checkout not confirmed');
  if (!mapsLink) throw new Error('Location link missing');

  function parseLatLngFromString(str) {
    const m = str.match(/(-?\d+\.\d+),(-?\d+\.\d+)/);
    if (m) return { lat: m[1], lng: m[2] };
    const dmsRegex = /(\d+)[\u00b0\u00ba]\s*(\d+)['′]\s*([\d.]+)["″]?\s*([NS])\s*(\d+)[\u00b0\u00ba]\s*(\d+)['′]\s*([\d.]+)["″]?\s*([EW])/i;
    const dms = str.match(dmsRegex);
    if (!dms) return null;
    const latSign = dms[4].toUpperCase() === 'S' ? -1 : 1;
    const lngSign = dms[8].toUpperCase() === 'W' ? -1 : 1;
    const lat = latSign * (parseInt(dms[1],10) + parseInt(dms[2],10)/60 + parseFloat(dms[3])/3600);
    const lng = lngSign * (parseInt(dms[5],10) + parseInt(dms[6],10)/60 + parseFloat(dms[7])/3600);
    return { lat: String(lat), lng: String(lng) };
  }
  const parsed = parseLatLngFromString(mapsLink);
  const gpsLat = parsed ? parsed.lat : '';
  const gpsLng = parsed ? parsed.lng : '';

  // Individual supply columns from the form
  const supplyColMap = {
    "Trash Bags \u2014 Qty Used": "Trash Bags",
    "All-Purpose Cleaner \u2014 Qty Used": "All-Purpose Cleaner",
    "Glass Cleaner \u2014 Qty Used": "Glass Cleaner",
    "Disinfectant \u2014 Qty Used": "Disinfectant",
    "Toilet Cleaner \u2014 Qty Used": "Toilet Cleaner",
    "Floor Cleaner \u2014 Qty Used": "Floor Cleaner",
    "Sponges \u2014 Qty Used": "Sponges",
    "Paper Towels \u2014 Qty Used": "Paper Towels",
    "Laundry Detergent \u2014 Qty Used": "Laundry Detergent",
    "Fabric Softener \u2014 Qty Used": "Fabric Softener",
    "Dish Soap \u2014 Qty Used": "Dish Soap",
    "Air Freshener \u2014 Qty Used": "Air Freshener",
    "Microfiber Cloths \u2014 Qty Used": "Microfiber Cloths",
    "Mop Pads \u2014 Qty Used": "Mop Pads",
  };
  const supplies = [];
  for (const [col, itemName] of Object.entries(supplyColMap)) {
    const raw = (get(col) || '').toString().trim();
    const qty = raw === '' ? 0 : parseInt(raw, 10);
    if (!isNaN(qty) && qty > 0) supplies.push({ itemName, quantityUsed: qty });
  }

  return [{ json: {
    bookingUid, cleanerIdFromForm, gpsLat, gpsLng,
    submissionTimestamp: (get('Timestamp') || new Date().toISOString()).toString(),
    processingStatus: 'PENDING', resultMessage: '', processedAt: '',
    hasError: false,
    issueReported, issueType, description, photoUrl, priority, lowStockAlert,
    supplies
  } }];
} catch (err) {
  const item = $('Normalize and Check').first().json;
  const get = (name) => { const v = item[name]; if (v !== undefined && v !== null) return v; const key = Object.keys(item).find(k => k.trim() === name); return key !== undefined ? item[key] : undefined; };
  return [{ json: { hasError: true, errorMessage: err.message, bookingUid: (get('Booking ID') || 'unknown').toString(), cleanerIdFromForm: (get('Cleaner ID') || '').toString(), submissionTimestamp: new Date().toISOString() } }];
}

// Look up cleaner email. Fall back to admin.
