  'iwshwh3eeeeansaksjasjasjajs':     { email: 'office@daydrinkingproperties.com', name: 'David Schmutz' },
  'jsljdjldjsljdjsdjsjdxmmxmxmxks':  { email: 'Kelly@daydrinkingproperties.com',  name: 'Kelly Williamson' },
  'eb68f11d-c077-409b-a3':           { email: 'sdrenske86@gmail.com',             name: 'Sarah Drenske' },
  'jsljdjldjsljdjsc2-ba96d3bf8af2':  { email: 'hollie.featherstone@gmail.com',    name: 'Hollie Featherstone' }
};

let recipientEmail = ADMIN_EMAIL;
let recipientName = 'Admin';
if (cleanerIdFromForm && cleanerMap[cleanerIdFromForm]) {
  recipientEmail = cleanerMap[cleanerIdFromForm].email;
  recipientName  = cleanerMap[cleanerIdFromForm].name;
}
return [{ json: { recipientEmail, recipientName, errorMessage, bookingUid, cleanerIdFromForm, submissionTimestamp: $json.submissionTimestamp || new Date().toISOString() } }];

const prev = $('Resolve Recipient').first().json;
const geminiResp = $input.first().json;
let simplifiedError = prev.errorMessage;
try { simplifiedError = geminiResp.candidates[0].content.parts[0].text.trim(); } catch (e) {}
return [{ json: { ...prev, simplifiedError } }];

const existing = $input.all();
let parsed;
let parsedFromShortLink;
let parsedFromDirect;
try { parsedFromShortLink = $('Parse Short Link Response').first().json; } catch (_) {}
try { parsedFromDirect = $('ParseAndValidate').first().json; } catch (_) {}

if (parsedFromShortLink && parsedFromDirect) {
  const tsA = new Date(parsedFromShortLink.submissionTimestamp || 0).getTime();
  const tsB = new Date(parsedFromDirect.submissionTimestamp || 0).getTime();
  parsed = tsA >= tsB ? parsedFromShortLink : parsedFromDirect;
} else {
  parsed = parsedFromShortLink || parsedFromDirect;
}
if (!parsed) throw new Error('Missing parsed submission');

const hasApproved = existing.some(i =>
  (i.json?.processingStatus ?? '').toString().trim() === 'APPROVED');
if (hasApproved) return [{ json: { skipInsert: true } }];
return [{ json: { ...parsed, skipInsert: false } }];

// supplies[] was built in ParseAndValidate / Parse Short Link Response.
// Emits one item per supply with qty > 0. Returns [] if none.
const bookingUid        = $json.bookingUid        || '';
const cleanerIdFromForm = $json.cleanerIdFromForm || '';
const loggedAt          = new Date().toISOString();
const supplies          = Array.isArray($json.supplies) ? $json.supplies : [];

if (!supplies.length) return [];

return supplies.map(({ itemName, quantityUsed }) => ({
  json: { bookingUid, cleanerIdFromForm, propertyUid: '', itemName, quantityUsed, loggedAt }
}));
